+import { useMemo, useState } from "react";
+
+const API_URL = import.meta.env.VITE_API_URL || "http://localhost:8000";
+
+function percent(value) {
+  return `${(value * 100).toFixed(2)}%`;
+}
+
+function App() {
+  const [url, setUrl] = useState("");
+  const [loading, setLoading] = useState(false);
+  const [error, setError] = useState("");
+  const [result, setResult] = useState(null);
+
+  const riskWidth = useMemo(() => {
+    if (!result) return "0%";
+    return `${Math.max(0, Math.min(100, result.risk_score * 100))}%`;
+  }, [result]);
+
+  async function handleScan() {
+    if (!url.trim()) {
+      setError("Enter a URL before scanning.");
+      return;
+    }
+
+    setLoading(true);
+    setError("");
+    setResult(null);
+
+    try {
+      const response = await fetch(`${API_URL}/scan`, {
+        method: "POST",
+        headers: { "Content-Type": "application/json" },
+        body: JSON.stringify({ url: url.trim() })
+      });
+
+      if (!response.ok) {
+        const payload = await response.json().catch(() => ({}));
+        throw new Error(payload.detail || "Scan failed");
+      }
+
+      const payload = await response.json();
+      setResult(payload);
+    } catch (err) {
+      setError(err.message || "Unable to connect to backend API.");
+    } finally {
+      setLoading(false);
+    }
+  }
+
+  return (
+    <div className="page">
+      <div className="card">
+        <h1>Phishing Website Detection</h1>
+        <p className="subtitle">
+          React frontend + Python backend with SHAP explainability.
+        </p>
+
+        <div className="input-row">
+          <input
+            value={url}
+            onChange={(e) => setUrl(e.target.value)}
+            placeholder="https://example.com/login"
+          />
+          <button onClick={handleScan} disabled={loading}>
+            {loading ? "Scanning..." : "Scan"}
+          </button>
+        </div>
+
+        {error && <div className="error">{error}</div>}
+
+        {result && (
+          <div className="result-wrap">
+            <div className="result-grid">
+              <div className="metric">
+                <div className="label">Prediction</div>
+                <div className={`value ${result.prediction}`}>
+                  {result.prediction.toUpperCase()}
+                </div>
+              </div>
+              <div className="metric">
+                <div className="label">Confidence</div>
+                <div className="value">{percent(result.confidence)}</div>
+              </div>
+              <div className="metric">
+                <div className="label">Phishing Probability</div>
+                <div className="value">{percent(result.phishing_probability)}</div>
+              </div>
+            </div>
+
+            <div className="risk-wrap">
+              <div className="label">Risk Bar</div>
+              <div className="risk-track">
+                <div className="risk-fill" style={{ width: riskWidth }} />
+              </div>
+              <div className="risk-text">{percent(result.risk_score)} risk</div>
+            </div>
+
+            <div className="top-features">
+              <h3>Top 5 Important Features (SHAP)</h3>
+              <table>
+                <thead>
+                  <tr>
+                    <th>Feature</th>
+                    <th>SHAP Value</th>
+                  </tr>
+                </thead>
+                <tbody>
+                  {result.top_features.map((item) => (
+                    <tr key={item.feature}>
+                      <td>{item.feature}</td>
+                      <td>{item.shap_value.toFixed(6)}</td>
+                    </tr>
+                  ))}
+                </tbody>
+              </table>
+            </div>
+
+            <div className="plot-wrap">
+              <h3>SHAP Explanation Chart</h3>
+              <img
+                src={`data:image/png;base64,${result.shap_plot_base64}`}
+                alt="SHAP chart"
+              />
+            </div>
+          </div>
+        )}
+      </div>
+    </div>
+  );
+}
+
+export default App;
